@MainActor final class RedeemCodeManager: ObservableObject { static let shared = RedeemCodeManager(); static let codePrefix = "CNET"; @Published var redemptionMessage: String?; @Published var isRedeeming = false; @AppStorage("invitation_expiry_timestamp") private var expiryTimestamp: Double = 0
