    func generateCodes(count: Int, note: String? = nil, modelContext: ModelContext) -> [RedeemCode] { var codes: [RedeemCode] = []; for _ in 0..<count {="" let="" code="Self.generateCode();" redeemcode="RedeemCode(code:" code,="" note:="" note);="" modelcontext.insert(redeemcode);="" codes.append(redeemcode)="" };="" try?="" modelcontext.save();="" return="" codes="" }="" func="" redeem(_="" rawcode:="" string,="" modelcontext:="" modelcontext)="" async="" -=""> Bool { isRedeeming = true; redemptionMessage = nil; defer { isRedeeming = false }; let code = rawCode.uppercased().trimmingCharacters(in: .whitespaces); guard code.hasPrefix(Self.codePrefix + "-"), code.count == 15, code.filter({ $0 == "-" }).count == 2 else { redemptionMessage = "邀请码格式不正确，应为 CNET-XXXX-XXXX"; return false }; let predicate = #Predicate<redeemcode> { $0.code == code }; let descriptor = FetchDescriptor<redeemcode>(predicate: predicate); guard let redeemCode = try? modelContext.fetch(descriptor).first else { redemptionMessage = "无效的邀请码"; return false }; guard !redeemCode.isUsed else { redemptionMessage = "此邀请码已被使用"; return false }; redeemCode.isUsed = true; redeemCode.usedAt = Date(); try? modelContext.save(); let oneYear = Date().addingTimeInterval(365 * 24 * 3600); expiryTimestamp = oneYear.timeIntervalSince1970; SubscriptionManager.shared.activateInvitation(until: oneYear); return true }
